import { TestBed } from '@angular/core/testing';
import { HttpClientTestingModule, HttpTestingController } from '@angular/common/http/testing';
import { EventService } from './event.service';

beforeEach(() => {
  TestBed.configureTestingModule({
    imports: [HttpClientTestingModule],
    providers: [EventService], // opcionális, mert providedIn:'root' is OK
  });
  service = TestBed.inject(EventService);
  httpMock = TestBed.inject(HttpTestingController);
});
```

Ha viszont standalone/`provideHttpClient` API-t használsz (újabb Angular verziókban), akkor a `provideHttpClientTesting()` provider változat használatos. Példa (standalone style):

```ts
import { TestBed } from '@angular/core/testing';
import { provideHttpClientTesting, HttpTestingController } from '@angular/common/http/testing';

beforeEach(() => {
  TestBed.configureTestingModule({
    providers: [provideHttpClientTesting()],
  });
  service = TestBed.inject(EventService);
  httpMock = TestBed.inject(HttpTestingController);
});
```

Teendők:
- Ellenőrizd, melyik stílust használja a projekted (NgModule vs. standalone).  
- Ha NgModule, használhatod a modul-alapú példát — ez a legrobosztusabb és kompatibilis minden Angular verzióval.
- Győződj meg róla, hogy a tesztek futtatásához a `@angular/common` csomag a megfelelő verzióban van (ez tartalmazza a `@angular/common/http/testing`-et).

Szeretnéd, hogy módosítsam a tesztfájlt a modul-alapú beállításra itt a repo-ban és futtassam a teszteket?

